/// <summary>
/// Extension of the <c>InventDim</c> table methods for the ETGSPAIN model.
/// </summary>
[ExtensionOf(tableStr(InventDim))]
final class InventDimETGSPAIN_Extension
{
}

Method.Source:
/// <summary>
/// New parameter for the new dimension.
/// </summary>
/// <param name="_applicationId">Parameter for the type of dimension.</param>
/// <returns>Returns the dimension.</returns>
public ETGSPAINInventApplicationId parmApplicationId(ETGSPAINInventApplicationId _applicationId = this.getValueForDimension(classStr(ETGSPAINInventTrackingDimension_Application)))
{
    if (CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        if (!prmIsDefault(_applicationId))
        {
            this.setValueForDimension(classStr(ETGSPAINInventTrackingDimension_Application), _applicationId);
        }
    }
    return _applicationId;
}

/// <summary>
/// ID of the field for the new dimension.
/// </summary>
/// <returns>Returns the field ID.</returns>
public static FieldID fieldIdApplicationId()
{
    FieldId fieldId = 0;

    if (CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        fieldId = InventDim::fieldIdForDimension(classStr(ETGSPAINInventTrackingDimension_Application));
    }

    return fieldId;
}

/// <summary>
/// Initializes the record with the corresponding dimensions.
/// </summary>
/// <param name="_ETGSPAINInventTransOperation">Buffer for <c>ETGSPAINInventTransOperation</c>.</param>
public void ETGSPAINinitFromETGSPAINInventTransOperation(ETGSPAINInventTransOperation _ETGSPAINInventTransOperation)
{
    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        _ETGSPAINInventTransOperation.checkInvalidFieldAccess(false);

        Enumerator inventDimFieldsEnumerator = InventDim::dimEnabledFieldList().getEnumerator();

        while (inventDimFieldsEnumerator.moveNext())
        {
            FieldId inventDimFieldId            = inventDimFieldsEnumerator.current();
            FieldId inventTransOperationFieldId = ETGSPAINInventTransOperation::getInventTransOperationFieldIdFromInventDimFieldId(inventDimFieldId);

            this.(inventDimFieldId) = _ETGSPAINInventTransOperation.(inventTransOperationFieldId);
        }
    }
}
